    def test_pre_build_gate_default_steps_run_full_loop_before_cleanup(self):
        steps = pre_build_gate.build_steps(
            base_url="http://127.0.0.1:8765",
            exercise_live_speech=False,
            exercise_visible_navigation=False,
            skip_python_tests=False,
            skip_full_loop=False,
            skip_cleanup=False,
        )

        self.assertEqual(
            [step["id"] for step in steps],
            [
                "python_safety_suite",
                "full_loop_regression",
                "stop_speaking_probe",
                "cleanup_chrome_test_tabs",
                "report_refresh",
            ],
        )
        full_loop_command = steps[1]["command"]
        self.assertIn("scripts/full_loop_regression.py", full_loop_command)
        self.assertIn("--case", full_loop_command)
        self.assertIn("all", full_loop_command)
        self.assertNotIn("--exercise-live-speech", full_loop_command)
        self.assertNotIn("--exercise-visible-navigation", full_loop_command)
        self.assertGreaterEqual(
            steps[1]["timeout_seconds"],
            sum(case["latency_budget_seconds"] for case in full_loop_regression.select_full_loop_cases("all")),
        )
        self.assertIn("scripts/probe_stop_speaking.py", steps[2]["command"])
        self.assertEqual(steps[2]["proof_contract"]["speech_mode"], "suppressed_for_stop_speaking")
        self.assertFalse(steps[2]["proof_contract"]["starts_audio"])
        self.assertIn("--close-duplicate-teams", steps[3]["command"])
        self.assertFalse(steps[3]["fatal"])

