    def test_stop_speaking_summary_uses_real_tool_reply(self):
        idle_stop = {
            "tool": "voice.stop_speaking",
            "status": "idle",
            "executed": True,
            "interrupted_previous": False,
            "reply": "I was not speaking.",
        }
        active_stop = {
            "tool": "voice.stop_speaking",
            "status": "stopped",
            "executed": True,
            "interrupted_previous": True,
            "reply": "Stopped speaking.",
        }

        with patch("jarvis.planner.stop_speaking", return_value=idle_stop):
            idle_result = Planner().handle("stop talking")
        with patch("jarvis.planner.stop_speaking", return_value=active_stop):
            active_result = Planner().handle("stop Jarvis speech")

        self.assertEqual(idle_result.tool, "voice.stop_speaking")
        self.assertEqual(idle_result.summary, "I was not speaking.")
        self.assertEqual(active_result.tool, "voice.stop_speaking")
        self.assertEqual(active_result.summary, "Stopped speaking.")

    def test_capability_status_reports_daily_memory_as_partial(self):
        result = capabilities_status()
        memory = next(item for item in result["capabilities"] if item["id"] == "memory")

        self.assertEqual(memory["status"], "partial")
        self.assertEqual(memory["test_prompt"], "daily memory summary")
        self.assertFalse(memory["needs_leo"])
        self.assertIn("Jarvis-to-Codex daily memory", memory["summary"])

    def test_capability_status_separates_prepared_from_live_features(self):
        result = capabilities_status()
        stt = next(item for item in result["capabilities"] if item["id"] == "speech_to_text")
        wake_audition = next(item for item in result["capabilities"] if item["id"] == "wake_audition_page")
        stt_audition = next(item for item in result["capabilities"] if item["id"] == "stt_audition_page")
        capability_questions = next(item for item in result["capabilities"] if item["id"] == "capability_questions")

        self.assertEqual(stt["status"], "partial")
        self.assertIn("Experimental command transcription", stt["summary"])
        self.assertEqual(wake_audition["status"], "prepared")
        self.assertEqual(stt_audition["status"], "prepared")
        self.assertEqual(capability_questions["status"], "prepared")
        self.assertEqual(capability_questions["test_prompt"], "open capability questions")
        self.assertIn("proof board", capability_questions["summary"])
        self.assertIn("/capability-questions/", capability_questions["page"])
        self.assertEqual(result["counts"]["prepared"], 3)
        self.assertIn("3 prepared", result["reply"])
        self.assertIn("capability questions proof board", result["reply"])
        self.assertGreaterEqual(result["counts"]["not_live"], 1)
        self.assertIn("hardened false-wake tuning", result["not_live_features"])
        self.assertIn("long-running wake listener reliability", result["not_live_features"])
        self.assertNotIn("real microphone speech-to-text", result["not_live_features"])
        self.assertNotIn("background wake-word listening", result["not_live_features"])
        self.assertNotIn("0 not ready", result["reply"])

