    def test_contact_data_remember_and_lookup_use_local_runtime_file(self):
        with tempfile.TemporaryDirectory() as temp_dir, \
             patch("jarvis.tools.CONTACT_DATA_PATH", Path(temp_dir) / "contact_aliases.json"):
            stored = contact_data_remember("Ms Sharpay", "Ms Darbus")
            found = contact_data_lookup("ms sharpay")
            titleless_found = contact_data_lookup("Sharpay")
            stt_found = contact_data_lookup("his Sharpay")
            status = contact_data_status()

        self.assertEqual(stored["status"], "stored")
        self.assertEqual(stored["alias"], "Ms Sharpay")
        self.assertEqual(found["status"], "found")
        self.assertEqual(found["alias"], "Ms Sharpay")
        self.assertEqual(found["display_name"], "Ms Darbus")
        self.assertEqual(titleless_found["status"], "found")
        self.assertEqual(titleless_found["display_name"], "Ms Darbus")
        self.assertEqual(stt_found["status"], "found")
        self.assertEqual(stt_found["alias"], "Ms Sharpay")
        self.assertEqual(stt_found["display_name"], "Ms Darbus")
        self.assertEqual(status["alias_count"], 1)
        self.assertEqual(status["aliases"][0]["alias"], "Ms Sharpay")
        self.assertFalse(stored["read_private_metadata"])
        self.assertFalse(stored["read_email_content"])
        self.assertFalse(found["read_private_metadata"])
        self.assertFalse(found["read_email_content"])
        self.assertFalse(status["read_private_metadata"])
        self.assertFalse(status["read_email_content"])

    def test_contact_data_infer_from_email_autostores_person_like_sender_match(self):
        mail_result = {
            "messages": [{"sender": "Sharpay Cao 曹宗悦"} for _ in range(6)],
            "scanned_count": 6,
        }
        with tempfile.TemporaryDirectory() as temp_dir, \
             patch("jarvis.tools.CONTACT_DATA_PATH", Path(temp_dir) / "contact_aliases.json"), \
             patch("jarvis.tools._find_executable", return_value="/usr/bin/osascript"), \
             patch("jarvis.tools.app_availability", return_value={"available": True}), \
             patch("jarvis.tools._apple_mail_messages", return_value=mail_result):
            inferred = jarvis_tools.contact_data_infer_from_email("Ms. Sharpay", scan_limit=50)
